class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        // Fixed 4x4 feature map for clarity in the solved example
        this.data = [12, 20, 30, 0, 8, 12, 2, 0, 34, 70, 37, 4, 112, 100, 25, 12];
        this.size = 4;
        this.colors = {
            bg: '#0f172a',
            grid: '#334155',
            text: '#f8fafc',
            highlight: '#3b82f6',
            success: '#10b981',
            muted: '#94a3b8'
        };
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = Math.max(500, this.container.clientHeight);
    }

    getSteps(inputs) {
        const k = inputs.kernelSize;
        const s = inputs.stride;
        const mode = inputs.poolingType === 0 ? "Max" : "Average";
        const steps = [
            {
                title: "Initialization",
                description: `We have a $4 \\times 4$ input feature map. With Kernel $K=${k}$ and Stride $S=${s}$, we calculate the output size: \\n\\n $$O = \\lfloor \\frac{4 - ${k}}{${s}} \\rfloor + 1 = ${Math.floor((4-k)/s) + 1}$$$\\n Total Output Grid: $${Math.floor((4-k)/s) + 1} \\times ${Math.floor((4-k)/s) + 1}$` 
            }
        ];

        let stepCount = 1;
        for (let y = 0; y <= this.size - k; y += s) {
            for (let x = 0; x <= this.size - k; x += s) {
                const vals = [];
                for(let i=0; i<k; i++) {
                    for(let j=0; j<k; j++) {
                        vals.push(this.data[(y+i)*this.size + (x+j)]);
                    }
                }
                const res = inputs.poolingType === 0 ? Math.max(...vals) : (vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1);
                steps.push({
                    title: `Step ${stepCount}: Local Region at (${x}, ${y})`,
                    description: `Extracting values from the $${k}\\times${k}$ window: **[${vals.join(', ')}]**. \\n\\n Applying **${mode}** calculation: \\n\\n $$Result = ${mode}(${vals.join(', ')}) = ${res}$$` 
                });
                stepCount++;
            }
        }

        steps.push({
            title: "Final Result",
            description: "The pooling operation is complete! Notice how the spatial resolution has been reduced while preserving the most important information (max) or global statistics (average)."
        });

        return steps;
    }

    render(inputs, stepIndex) {
        const { ctx, canvas, colors, data, size } = this;
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const k = inputs.kernelSize;
        const s = inputs.stride;
        const cellSize = 50;
        const gridOffset = 80;
        const outW = Math.floor((size - k)/s) + 1;

        const centerX = canvas.width / 2;
        const inputStartX = centerX - 220;
        const outputStartX = centerX + 80;

        // Draw Input Grid Title
        ctx.fillStyle = colors.muted;
        ctx.font = "600 16px Inter, sans-serif";
        ctx.textAlign = "left";
        ctx.fillText("INPUT FEATURE MAP (4x4)", inputStartX, gridOffset - 30);

        // Helper to get coordinates for sliding window
        const windows = [];
        for(let y=0; y<=size-k; y+=s) for(let x=0; x<=size-k; x+=s) windows.push({x,y});

        // Draw Input Grid Cells
        for (let i = 0; i < 16; i++) {
            const r = Math.floor(i / size);
            const c = i % size;
            const xPos = inputStartX + c * cellSize;
            const yPos = gridOffset + r * cellSize;

            ctx.strokeStyle = colors.grid;
            ctx.lineWidth = 1;
            ctx.strokeRect(xPos, yPos, cellSize, cellSize);

            ctx.fillStyle = colors.text;
            ctx.textAlign = "center";
            ctx.font = "14px Monospace";
            ctx.fillText(data[i], xPos + cellSize/2, yPos + cellSize/2 + 5);
        }

        // Highlight specific input window
        if (stepIndex > 0 && stepIndex <= windows.length) {
            const active = windows[stepIndex - 1];
            ctx.lineWidth = 4;
            ctx.strokeStyle = colors.highlight;
            ctx.strokeRect(inputStartX + active.x * cellSize, gridOffset + active.y * cellSize, k * cellSize, k * cellSize);

            // Draw connection line
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(inputStartX + (active.x + k)*cellSize, gridOffset + active.y*cellSize);
            ctx.lineTo(outputStartX, gridOffset);
            ctx.stroke();
            ctx.setLineDash([]);
        }

        // Draw Output Grid
        ctx.fillStyle = colors.muted;
        ctx.textAlign = "left";
        ctx.fillText(`OUTPUT (${outW}x${outW})`, outputStartX, gridOffset - 30);

        for (let i = 0; i < outW * outW; i++) {
            const r = Math.floor(i / outW);
            const c = i % outW;
            const xPos = outputStartX + c * cellSize;
            const yPos = gridOffset + r * cellSize;

            ctx.strokeStyle = colors.grid;
            ctx.lineWidth = 1;
            ctx.strokeRect(xPos, yPos, cellSize, cellSize);

            // Fill results for completed steps
            if (stepIndex > 0 && (i < stepIndex || stepIndex > windows.length)) {
                const win = windows[i];
                const localVals = [];
                for(let py=0; py<k; py++) for(let px=0; px<k; px++) localVals.push(data[(win.y+py)*size + (win.x+px)]);
                const res = inputs.poolingType === 0 ? Math.max(...localVals) : (localVals.reduce((a,b)=>a+b,0)/localVals.length).toFixed(1);

                ctx.fillStyle = (i === stepIndex - 1) ? colors.success : colors.text;
                ctx.font = "bold 14px Monospace";
                ctx.textAlign = "center";
                ctx.fillText(res, xPos + cellSize/2, yPos + cellSize/2 + 5);
            }
        }
    }
}
